# Core logic extracted from the original desktop app for Streamlit use.

import os
import re
import io
import base64
import subprocess
from decimal import Decimal, ROUND_HALF_UP

import fitz
import pandas as pd
from PIL import Image, ImageDraw, ImageFont

APP_TITLE = "PDF katalogo kainų programa"
AUTHOR_TEXT = "Autorius Vytautas Žilys"
LOGO_B64 = """"""

TOC_BG_B64 = """"""

def load_toc_background_stream():
    return base64.b64decode(TOC_BG_B64)

def load_logo_image(max_size=(110, 110)):
    raw = base64.b64decode(LOGO_B64)
    img = Image.open(io.BytesIO(raw)).convert("RGBA")
    img.thumbnail(max_size, Image.LANCZOS)
    return img


def norm_text(s):
    s = "" if s is None or (isinstance(s, float) and pd.isna(s)) else str(s)
    s = s.replace("\n", " ").replace("\r", " ").strip()
    s = re.sub(r"\s+", " ", s)
    return s


def norm_key(s):
    s = norm_text(s).upper()
    s = re.sub(r"[^A-Z0-9]", "", s)
    return s


def parse_percent(text):
    t = norm_text(text).replace("%", "").replace(",", ".")
    if not t:
        return 0.0
    return float(t)


def fmt_eur(value):
    d = Decimal(str(value)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    s = f"{d:.2f}".replace(".", ",")
    return f"{s} €"


def detect_code_and_price_columns(df_raw):
    max_rows = min(len(df_raw), 50)
    for r in range(max_rows):
        row = [norm_text(x).lower() for x in df_raw.iloc[r].tolist()]
        code_idx = None
        price_su_idx = None
        price_any_idx = None
        for i, cell in enumerate(row):
            if code_idx is None and cell == "kodas":
                code_idx = i
            elif code_idx is None and "kodas" in cell:
                code_idx = i

            if "kaina" in cell and "pvm" in cell:
                if "su" in cell and price_su_idx is None:
                    price_su_idx = i
                elif price_any_idx is None:
                    price_any_idx = i

        price_idx = price_su_idx if price_su_idx is not None else price_any_idx
        if code_idx is not None and price_idx is not None:
            return r, code_idx, price_idx
    return None, None, None


def _open_excel_with_fallback(excel_path):
    try:
        return pd.ExcelFile(excel_path), excel_path
    except Exception as first_exc:
        ext = os.path.splitext(excel_path)[1].lower()
        if ext != ".xls":
            raise first_exc

        out_dir = os.path.join(os.path.dirname(excel_path), "_xlsx_cache")
        os.makedirs(out_dir, exist_ok=True)
        converted_path = os.path.join(out_dir, os.path.splitext(os.path.basename(excel_path))[0] + ".xlsx")

        need_convert = (not os.path.exists(converted_path)) or (
            os.path.getmtime(converted_path) < os.path.getmtime(excel_path)
        )

        if need_convert:
            import subprocess
            result = subprocess.run(
                [
                    "soffice",
                    "--headless",
                    "-env:UserInstallation=file:///tmp/libreoffice_oai_profile",
                    "--convert-to",
                    "xlsx",
                    "--outdir",
                    out_dir,
                    excel_path,
                ],
                capture_output=True,
                text=True,
            )
            if result.returncode != 0 or not os.path.exists(converted_path):
                raise ValueError(
                    "Nepavyko atidaryti XLS failo. Išsaugok jį kaip XLSX arba įdiek Excel skaitymo palaikymą."
                ) from first_exc

        return pd.ExcelFile(converted_path), converted_path


def _find_price_column(headers, price_mode):
    header_map = [(h, norm_text(h).lower().replace(" ", "")) for h in headers]

    su_candidates = [h for h, n in header_map if "kaina" in n and "supvm" in n]
    be_candidates = [h for h, n in header_map if "kaina" in n and "bepvm" in n]
    generic_candidates = [h for h, n in header_map if "kaina" in n and "pvm" in n]

    if price_mode == "be_pvm":
        if be_candidates:
            return be_candidates[0]
        if generic_candidates:
            for h in generic_candidates:
                n = norm_text(h).lower().replace(" ", "")
                if "be" in n:
                    return h
    else:
        if su_candidates:
            return su_candidates[0]
        if generic_candidates:
            for h in generic_candidates:
                n = norm_text(h).lower().replace(" ", "")
                if "su" in n:
                    return h

    return None


def load_prices(excel_path, price_mode="su_pvm"):
    xls, actual_excel_path = _open_excel_with_fallback(excel_path)
    for sheet_name in xls.sheet_names:
        try:
            df_raw = pd.read_excel(actual_excel_path, sheet_name=sheet_name, header=None)
        except Exception:
            continue

        header_row, code_col_idx, detected_price_idx = detect_code_and_price_columns(df_raw)
        if header_row is None:
            continue

        df = pd.read_excel(actual_excel_path, sheet_name=sheet_name, header=header_row)
        headers = list(df.columns)
        code_col = headers[code_col_idx]
        price_col = _find_price_column(headers, price_mode)
        if price_col is None:
            price_col = headers[detected_price_idx]

        prices = {}
        for _, row in df.iterrows():
            code = norm_key(row.get(code_col, ""))
            price = row.get(price_col, None)
            if not code:
                continue
            try:
                price = float(str(price).replace(" ", "").replace(",", ".").strip())
            except Exception:
                continue
            prices[code] = price

        if prices:
            return prices, sheet_name, code_col, price_col

    raise ValueError("Nepavyko rasti Excel stulpelių 'Kodas' ir pasirinkto kainos tipo (su PVM / be PVM).")

def find_group_title(page):
    words = page.get_text("words")
    if not words:
        return f"Lapas {page.number + 1}"

    # Ieškom viršutinės zonos teksto, paimame didžiausio šrifto bloką pagal aukštį
    top_words = [w for w in words if w[1] < page.rect.height * 0.18]
    if not top_words:
        top_words = words

    # grupuojam pagal eilutę
    lines = {}
    for w in top_words:
        key = (round(w[1], 1), round(w[3], 1))
        lines.setdefault(key, []).append(w)

    best_text = None
    best_score = -1
    for _, ws in lines.items():
        ws = sorted(ws, key=lambda x: x[0])
        text = " ".join(str(w[4]) for w in ws).strip()
        if not text:
            continue
        avg_h = sum((w[3] - w[1]) for w in ws) / max(len(ws), 1)
        score = avg_h * min(len(text), 40)
        if score > best_score and len(text) >= 3:
            best_score = score
            best_text = text

    return best_text if best_text else f"Lapas {page.number + 1}"






def _extract_text_blocks(page):
    text_blocks = []
    for block in page.get_text("dict")["blocks"]:
        if block.get("type", 0) != 0:
            continue

        lines = []
        for line in block.get("lines", []):
            spans = line.get("spans", [])
            if not spans:
                continue

            txt = norm_text("".join(span.get("text", "") for span in spans))
            if not txt:
                continue

            x0 = min(span["bbox"][0] for span in spans)
            y0 = min(span["bbox"][1] for span in spans)
            x1 = max(span["bbox"][2] for span in spans)
            y1 = max(span["bbox"][3] for span in spans)
            lines.append((fitz.Rect(x0, y0, x1, y1), txt))

        if lines:
            text_blocks.append({
                "rect": fitz.Rect(block["bbox"]),
                "lines": lines,
                "text": " ".join(txt for _, txt in lines),
            })

    return text_blocks


def _group_row_centers(image_rects, tolerance=45):
    centers = sorted((rect.y0 + rect.y1) / 2.0 for rect in image_rects)
    if not centers:
        return []

    groups = [[centers[0]]]
    for center in centers[1:]:
        current_avg = sum(groups[-1]) / len(groups[-1])
        if abs(center - current_avg) <= tolerance:
            groups[-1].append(center)
        else:
            groups.append([center])

    return [sum(group) / len(group) for group in groups]


def _pick_product_images(page):
    """
    Kataloge vienas produktas = vienas pagrindinis paveikslėlis.
    Kai tame pačiame langelyje PDF turi kelis image blokus, paliekam didžiausią.
    """
    image_rects = [
        fitz.Rect(block["bbox"])
        for block in page.get_text("dict")["blocks"]
        if block.get("type", 0) == 1
    ]
    if not image_rects:
        return []

    page_rect = page.rect
    col_width = page_rect.width / 3.0
    row_centers = _group_row_centers(image_rects)
    if not row_centers:
        return []

    row_bottoms = [
        (row_centers[i] + row_centers[i + 1]) / 2.0
        for i in range(len(row_centers) - 1)
    ] + [page_rect.height - 20]

    best_by_cell = {}
    for rect in image_rects:
        cx = (rect.x0 + rect.x1) / 2.0
        cy = (rect.y0 + rect.y1) / 2.0
        col = max(0, min(2, int(cx / col_width)))
        row = min(range(len(row_centers)), key=lambda i: abs(cy - row_centers[i]))
        cell_key = (row, col)
        area = rect.width * rect.height

        prev = best_by_cell.get(cell_key)
        if prev is None or area > prev["area"]:
            best_by_cell[cell_key] = {
                "row": row,
                "col": col,
                "rect": rect,
                "area": area,
                "row_bottom": row_bottoms[row],
            }

    return [best_by_cell[key] for key in sorted(best_by_cell.keys())]


def _extract_code_from_first_line(first_line_text):
    """
    Taisyklė pagal tavo katalogą:
    - kodas yra pirmoje eilutėje po paveikslėliu
    - imama tik dalis iki pirmo kablelio
    - iš jos imamas tik pirmas tokenas
    - tokene turi būti bent viena raidė ir bent vienas skaičius
    """
    first_line_text = norm_text(first_line_text)
    if not first_line_text or "," not in first_line_text:
        return None, None

    before_comma = norm_text(first_line_text.split(",", 1)[0])
    if not before_comma:
        return None, None

    token = before_comma.split(" ")[0].strip()
    normalized = norm_key(token)
    if len(normalized) < 5:
        return None, None
    if not re.fullmatch(r"[A-Z0-9]+", normalized):
        return None, None
    if not re.search(r"[A-Z]", normalized):
        return None, None

    return normalized, token


def build_code_index(page):
    """
    Stabili logika:
    - produktai nustatomi pagal paveikslėlius, ne pagal bet kokį tekstą
    - vienam 3x4 langeliui leidžiamas tik vienas produktas
    - tekstas imamas tik po to paties produkto paveikslėliu
    - kodas imamas tik iš pirmos aprašo eilutės iki pirmo kablelio
    """
    text_blocks = _extract_text_blocks(page)
    product_images = _pick_product_images(page)
    if not product_images:
        return []

    page_rect = page.rect
    col_width = page_rect.width / 3.0
    results = []

    for item in product_images:
        img_rect = item["rect"]
        row = item["row"]
        col = item["col"]

        cell_x0 = col * col_width
        cell_x1 = (col + 1) * col_width
        cell_y0 = max(img_rect.y1 - 3, img_rect.y0)
        cell_y1 = item["row_bottom"]

        candidate_blocks = []
        for block in text_blocks:
            block_rect = block["rect"]
            block_cx = (block_rect.x0 + block_rect.x1) / 2.0

            if not (cell_x0 <= block_cx < cell_x1):
                continue
            if block_rect.y0 < cell_y0 or block_rect.y0 >= cell_y1:
                continue

            candidate_blocks.append(block)

        candidate_blocks.sort(key=lambda b: (b["rect"].y0, b["rect"].x0))
        if not candidate_blocks:
            continue

        first_block = candidate_blocks[0]
        first_line_rect, first_line_text = first_block["lines"][0]
        code, raw_token = _extract_code_from_first_line(first_line_text)
        if not code:
            continue

        desc_rect = fitz.Rect(first_block["rect"])
        for block in candidate_blocks[1:]:
            desc_rect |= block["rect"]

        results.append({
            "code": code,
            "raw": raw_token,
            "rect": desc_rect,
            "code_line_rect": first_line_rect,
            "desc_rect": desc_rect,
            "image_rect": img_rect,
            "row": row,
            "col": col,
            "block_no": None,
        })

    return results


def looks_like_real_code_for_report(code):
    """
    Ataskaitai paliekam tą patį griežtą produkto kodo formatą,
    bet nebeatmetam vien raidinių kodų, nes kataloge tokių yra.
    """
    if not code:
        return False
    if len(code) < 5:
        return False
    if not re.match(r"^[A-Z0-9]+$", code):
        return False
    if not re.search(r"[A-Z]", code):
        return False
    return True

def block_for_code(page, item):
    return item.get("desc_rect") or item["rect"]


def find_font_file():
    candidates = [
        r"C:\Windows\Fonts\arial.ttf",
        r"C:\Windows\Fonts\ARIAL.TTF",
        r"C:\Windows\Fonts\segoeui.ttf",
        r"C:\Windows\Fonts\calibri.ttf",
        "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/dejavu/DejaVuSans.ttf",
    ]
    for path in candidates:
        if os.path.exists(path):
            return path
    return None


def _ensure_unicode_font(page, preferred_name="ltfont"):
    font_path = find_font_file()
    if not font_path:
        return "helv", None
    return preferred_name, font_path


def _load_pil_font(font_path, size):
    try:
        if font_path and os.path.exists(font_path):
            return ImageFont.truetype(font_path, size)
    except Exception:
        pass
    try:
        return ImageFont.truetype("DejaVuSans.ttf", size)
    except Exception:
        return ImageFont.load_default()


def _measure_text(text, font_path, fontsize):
    font = _load_pil_font(font_path, max(1, int(round(fontsize))))
    bbox = font.getbbox(text or " ")
    return max(1, bbox[2] - bbox[0]), max(1, bbox[3] - bbox[1])


def insert_unicode_text(page, point, text, fontsize=12, font_path=None, color=(0, 0, 0), anchor="lt"):
    if not text:
        return fitz.Rect(point.x, point.y, point.x + 1, point.y + 1)

    scale = 4
    w_px, h_px = _measure_text(text, font_path, max(1, int(round(fontsize * scale))))
    pad = 10
    img = Image.new("RGBA", (w_px + pad * 2, h_px + pad * 2), (255, 255, 255, 0))
    draw = ImageDraw.Draw(img)
    font = _load_pil_font(font_path, max(1, int(round(fontsize * scale))))
    rgb = tuple(int(max(0, min(1, c)) * 255) for c in color)
    draw.text((pad, pad), text, font=font, fill=rgb + (255,))

    buf = io.BytesIO()
    img.save(buf, format="PNG")

    width_pt = (w_px + pad * 2) * 72.0 / (96.0 * scale)
    height_pt = (h_px + pad * 2) * 72.0 / (96.0 * scale)

    x = point.x
    y = point.y
    if anchor == "lm":
        y = point.y - height_pt / 2.0
    elif anchor == "mm":
        x = point.x - width_pt / 2.0
        y = point.y - height_pt / 2.0

    rect = fitz.Rect(x, y, x + width_pt, y + height_pt)
    page.insert_image(rect, stream=buf.getvalue(), overlay=True)
    return rect


def insert_unicode_textbox(page, rect, text, fontsize=12, font_path=None, color=(0,0,0), align=0):
    text = text or ""
    if not text:
        return

    scale = 4
    font = _load_pil_font(font_path, max(1, int(round(fontsize * scale))))
    max_w_px = max(1, int(rect.width * 96.0 / 72.0 * scale) - 24)

    words = text.split()
    lines = []
    current = ""
    for word in words:
        test = word if not current else current + " " + word
        bbox = font.getbbox(test)
        tw = bbox[2] - bbox[0]
        if tw <= max_w_px or not current:
            current = test
        else:
            lines.append(current)
            current = word
    if current:
        lines.append(current)
    if not lines:
        lines = [text]

    line_boxes = [font.getbbox(line or " ") for line in lines]
    widths = [max(1, b[2]-b[0]) for b in line_boxes]
    heights = [max(1, b[3]-b[1]) for b in line_boxes]
    total_h = sum(heights) + max(0, len(lines)-1) * int(8 * scale / 4)
    img_w = max(widths) + 24
    img_h = total_h + 24

    img = Image.new("RGBA", (img_w, img_h), (255,255,255,0))
    draw = ImageDraw.Draw(img)
    rgb = tuple(int(max(0, min(1, c)) * 255) for c in color)

    y = 12
    for line, w, h in zip(lines, widths, heights):
        if align == 1:
            x = (img_w - w) // 2
        elif align == 2:
            x = img_w - w - 12
        else:
            x = 12
        draw.text((x, y), line, font=font, fill=rgb + (255,))
        y += h + int(8 * scale / 4)

    buf = io.BytesIO()
    img.save(buf, format="PNG")
    width_pt = img_w * 72.0 / (96.0 * scale)
    height_pt = img_h * 72.0 / (96.0 * scale)
    target = fitz.Rect(rect.x0, rect.y0, min(rect.x0 + width_pt, rect.x1), min(rect.y0 + height_pt, rect.y1))
    page.insert_image(target, stream=buf.getvalue(), overlay=True)


def draw_centered_text(page, rect, text, fontsize):
    _font_name, font_path = _ensure_unicode_font(page, preferred_name="pricefont")
    center = fitz.Point((rect.x0 + rect.x1) / 2.0, (rect.y0 + rect.y1) / 2.0)
    insert_unicode_text(
        page,
        center,
        text,
        fontsize=fontsize,
        font_path=font_path,
        color=(0, 0, 0),
        anchor="mm",
    )


def draw_price_circle(page, block_rect, price_text, code_line_rect=None, bubble_style="classic"):
    """
    Kaina dedama:
    - šiek tiek virš pirmos aprašo eilutės
    - dešinys apskritimo kraštas lygiuojamas su dešiniausiu aprašo simboliu
    """
    radius = 23
    gap_up = 4

    desc_rect = block_rect
    if code_line_rect is None:
        code_line_rect = block_rect

    cx = desc_rect.x1 - radius
    cy = code_line_rect.y0 - gap_up - radius

    page_rect = page.rect
    cx = max(radius + 2, min(cx, page_rect.x1 - radius - 2))
    cy = max(radius + 2, min(cy, page_rect.y1 - radius - 2))

    circle = fitz.Rect(cx - radius, cy - radius, cx + radius, cy + radius)

    if bubble_style == "modern":
        shadow = fitz.Rect(circle.x0 + 1.2, circle.y0 + 1.8, circle.x1 + 1.2, circle.y1 + 1.8)
        shape = page.new_shape()
        shape.draw_oval(shadow)
        shape.finish(color=(0.78, 0.67, 0.08), fill=(0.92, 0.82, 0.08), width=0.4)
        shape.commit()

        shape = page.new_shape()
        shape.draw_oval(circle)
        shape.finish(color=(0.08, 0.08, 0.08), fill=(0.98, 0.90, 0.20), width=1.2)
        shape.commit()

        inner = fitz.Rect(circle.x0 + 3, circle.y0 + 3, circle.x1 - 3, circle.y1 - 3)
        shape = page.new_shape()
        shape.draw_oval(inner)
        shape.finish(color=None, fill=(1.0, 0.95, 0.34), width=0)
        shape.commit()
    else:
        shape = page.new_shape()
        shape.draw_oval(circle)
        shape.finish(color=(0, 0, 0), fill=(1, 0.9, 0.2), width=1.1)
        shape.commit()

    font_size = 12.5
    if len(price_text) >= 8:
        font_size = 11.5
    if len(price_text) >= 10:
        font_size = 10.5

    draw_centered_text(page, circle, price_text, font_size)


def add_group_titles(doc):
    titles = []
    for page in doc:
        title = find_group_title(page)
        titles.append(title)
        header_rect = fitz.Rect(24, 10, page.rect.width - 24, 30)
        _font_name, font_path = _ensure_unicode_font(page)
        try:
            insert_unicode_textbox(page, header_rect, title, fontsize=11, font_path=font_path, color=(0, 0, 0), align=1)
        except Exception:
            pass
    return titles



def build_contents_pdf(page_width, page_height, group_titles):
    # unikalios grupės ir pirmi puslapiai originaliame dokumente (0-indeksu)
    groups = []
    seen = set()
    for i, t in enumerate(group_titles):
        key = norm_text(t)
        if key not in seen:
            seen.add(key)
            groups.append((t, i))

    toc_doc = fitz.open()
    page = toc_doc.new_page(width=page_width, height=page_height)
    _font_name, font_path = _ensure_unicode_font(page)

    title_font = 20
    left_margin = 28
    right_margin = 28
    gutter = 12
    top_y = 30
    start_y = 68
    bottom_margin = 24
    col_count = 2

    insert_unicode_text(
        page,
        fitz.Point(left_margin, top_y),
        "Turinys",
        fontsize=title_font,
        font_path=font_path,
        color=(0, 0, 0),
        anchor="lt",
    )

    size_candidates = [16, 15.5, 15, 14.5, 14, 13.5, 13, 12.5, 12]
    chosen_font = size_candidates[-1]
    chosen_line_h = 16
    for candidate in size_candidates:
        candidate_line_h = max(candidate + 5.5, candidate * 1.34)
        usable_height = page.rect.height - start_y - bottom_margin
        rows_per_col = max(1, int(usable_height // candidate_line_h))
        if len(groups) <= rows_per_col * col_count:
            chosen_font = candidate
            chosen_line_h = candidate_line_h
            break

    body_font = chosen_font
    line_h = chosen_line_h
    usable_height = page.rect.height - start_y - bottom_margin
    rows_per_col = max(1, int(usable_height // line_h))

    col_width = (page.rect.width - left_margin - right_margin - gutter) / 2.0
    columns_x = [left_margin, left_margin + col_width + gutter]

    visible_groups = groups[: rows_per_col * col_count]
    overflow_groups = groups[rows_per_col * col_count :]

    links = []
    dot = "."
    dot_width = _measure_text(dot, font_path, body_font)[0] * 72.0 / 96.0

    for idx, (title, target_original_page) in enumerate(visible_groups):
        col = 0 if idx < rows_per_col else 1
        row = idx if col == 0 else idx - rows_per_col
        x = columns_x[col]
        y = start_y + row * line_h

        page_no_text = str(target_original_page + 1)
        num_width = _measure_text(page_no_text, font_path, body_font)[0] * 72.0 / 96.0

        num_box_w = max(18, num_width + 2)
        number_right_x = x + col_width
        number_left_x = number_right_x - num_box_w

        title_max_w = max(20, col_width - num_box_w - 14)
        safe_title = title
        title_width = _measure_text(safe_title, font_path, body_font)[0] * 72.0 / 96.0
        if title_width > title_max_w:
            while safe_title and (_measure_text(safe_title + "…", font_path, body_font)[0] * 72.0 / 96.0) > title_max_w:
                safe_title = safe_title[:-1]
            safe_title = (safe_title.rstrip() + "…") if safe_title else "…"
            title_width = _measure_text(safe_title, font_path, body_font)[0] * 72.0 / 96.0

        # Pavadinimas kairėje
        title_rect = fitz.Rect(x, y - 1, number_left_x - 8, y + line_h)
        insert_unicode_textbox(
            page,
            title_rect,
            safe_title,
            fontsize=body_font,
            font_path=font_path,
            color=(0, 0, 0),
            align=0,
        )

        # Taškeliai tarp pavadinimo ir numerio
        dots_start_x = x + title_width + 6
        dots_end_x = number_left_x - 4
        if dots_end_x > dots_start_x + dot_width * 2:
            dots_count = max(2, int((dots_end_x - dots_start_x) / max(dot_width, 1)))
            dots_text = dot * dots_count
            dots_point = fitz.Point(dots_start_x, y)
            insert_unicode_text(
                page,
                dots_point,
                dots_text,
                fontsize=body_font,
                font_path=font_path,
                color=(0.25, 0.25, 0.25),
                anchor="lt",
            )

        # Puslapio numeris griežtai lygiuotas dešinėje
        num_rect = fitz.Rect(number_left_x, y - 1, number_right_x, y + line_h)
        insert_unicode_textbox(
            page,
            num_rect,
            page_no_text,
            fontsize=body_font,
            font_path=font_path,
            color=(0, 0, 0),
            align=2,
        )

        rect = fitz.Rect(x, y - 2, x + col_width, y + line_h)
        links.append((page.number, rect, target_original_page))

    if overflow_groups:
        note = f"Ir dar {len(overflow_groups)} grup."
        insert_unicode_text(
            page,
            fitz.Point(columns_x[1], page.rect.height - 14),
            note,
            fontsize=8.5,
            font_path=font_path,
            color=(0.35, 0.35, 0.35),
            anchor="lb",
        )

    # Logotipas turinio lapo dešiniajame apatiniame kampe.
    try:
        logo_bytes = base64.b64decode(LOGO_B64)
        logo_w = 118
        logo_h = 118
        margin_x = 18
        margin_y = 18
        logo_rect = fitz.Rect(
            page.rect.width - margin_x - logo_w,
            page.rect.height - margin_y - logo_h,
            page.rect.width - margin_x,
            page.rect.height - margin_y,
        )
        page.insert_image(logo_rect, stream=logo_bytes, keep_proportion=True, overlay=True)
    except Exception:
        pass

    return toc_doc, links


def process_catalog(pdf_path, excel_path, out_pdf, report_missing_excel_path, report_missing_pdf_path, percent, progress_cb=None, include_contents=False, price_mode="su_pvm", bubble_style="classic"):
    prices, sheet_name, code_col, price_col = load_prices(excel_path, price_mode=price_mode)
    doc = fitz.open(pdf_path)

    matched = 0
    used = set()
    seen_pdf_codes_all = set()
    seen_pdf_codes_report = set()
    total_pages = len(doc)

    for page_index, page in enumerate(doc):
        code_items = build_code_index(page)
        for item in code_items:
            code = item["code"]
            seen_pdf_codes_all.add(code)
            if looks_like_real_code_for_report(code):
                seen_pdf_codes_report.add(code)

            if code in prices and code not in used:
                block_rect = block_for_code(page, item)
                base_price = prices[code]
                final_price = base_price * (1 + percent / 100.0)
                draw_price_circle(page, block_rect, fmt_eur(final_price), item.get("code_line_rect"), bubble_style=bubble_style)
                matched += 1
                used.add(code)

        if progress_cb:
            progress_cb(page_index + 1, total_pages, matched, len(seen_pdf_codes_report))

    group_titles = add_group_titles(doc)

    if include_contents:
        first_rect = doc[0].rect
        toc_doc, toc_links = build_contents_pdf(first_rect.width, first_rect.height, group_titles)
        toc_page_count = len(toc_doc)

        final_doc = fitz.open()
        final_doc.insert_pdf(toc_doc)
        final_doc.insert_pdf(doc)

        for toc_page_no, rect, target_original_page in toc_links:
            final_doc[toc_page_no].insert_link({
                "kind": fitz.LINK_GOTO,
                "from": rect,
                "page": target_original_page + toc_page_count,
            })

        # Kiekviename katalogo puslapyje pridedame paspaudžiamą nuorodą atgal į turinį.
        for page_no in range(toc_page_count, len(final_doc)):
            page = final_doc[page_no]
            _font_name, font_path = _ensure_unicode_font(page)
            label = "← Turinys"
            font_size = 8.8
            text_w = _measure_text(label, font_path, font_size)[0] * 72.0 / 96.0
            pad_x = 4
            rect_w = text_w + pad_x * 2
            rect_h = 12
            x1 = page.rect.width - 12
            x0 = max(12, x1 - rect_w)
            y0 = 7
            y1 = y0 + rect_h
            link_rect = fitz.Rect(x0, y0, x1, y1)

            try:
                insert_unicode_textbox(
                    page,
                    link_rect,
                    label,
                    fontsize=font_size,
                    font_path=font_path,
                    color=(0, 0, 0.9),
                    align=2,
                )
            except Exception:
                page.insert_text(
                    fitz.Point(x0 + 1, y1 - 2),
                    "Turinys",
                    fontsize=8,
                    fontname="helv",
                    color=(0, 0, 0.9),
                )

            page.insert_link({
                "kind": fitz.LINK_GOTO,
                "from": link_rect,
                "page": 0,
            })

        doc.close()
        toc_doc.close()
        doc = final_doc

    missing_in_pdf = sorted(set(prices.keys()) - used)
    missing_in_excel = sorted(seen_pdf_codes_report - set(prices.keys()))

    compression_applied = False
    compression_message = "PDF sukurtas be papildomo suspaudimo."
    original_size = None

    doc.save(out_pdf, garbage=4, deflate=True)
    final_size = os.path.getsize(out_pdf) if os.path.exists(out_pdf) else None

    with open(report_missing_pdf_path, "w", encoding="utf-8") as f:
        f.write(f"Naudotas Excel lapas: {sheet_name}\n")
        f.write(f"Kodo stulpelis: {code_col}\n")
        f.write(f"Kainos stulpelis: {price_col}\n")
        f.write(f"Pritaikyta korekcija (%): {percent}\n")
        f.write(f"Rastų PDF kandidatų iš viso: {len(seen_pdf_codes_all)}\n")
        f.write(f"Rastų PDF kodų ataskaitai: {len(seen_pdf_codes_report)}\n")
        f.write(f"Priskirta kainų: {matched}\n")
        f.write(f"Excel kodų, kurių nėra PDF faile: {len(missing_in_pdf)}\n\n")
        if missing_in_pdf:
            f.write("EXCEL KODAI, KURIŲ NERASTA PDF FAILE:\n")
            for c in missing_in_pdf:
                f.write(c + "\n")

    with open(report_missing_excel_path, "w", encoding="utf-8") as f:
        f.write(f"Naudotas Excel lapas: {sheet_name}\n")
        f.write(f"Rastų PDF kandidatų iš viso: {len(seen_pdf_codes_all)}\n")
        f.write(f"Rastų PDF kodų ataskaitai: {len(seen_pdf_codes_report)}\n")
        f.write(f"PDF kodų, kurių nėra Excel lentelėje: {len(missing_in_excel)}\n\n")
        if missing_in_excel:
            f.write("PDF KODAI, KURIŲ NĖRA EXCEL LENTELĖJE:\n")
            for c in missing_in_excel:
                f.write(c + "\n")

    final_size_mb = round(final_size / (1024 * 1024), 2) if final_size else None
    original_size_mb = round(original_size / (1024 * 1024), 2) if original_size else None

    return {
        "matched": matched,
        "missing_in_pdf": len(missing_in_pdf),
        "missing_in_excel": len(missing_in_excel),
        "sheet_name": sheet_name,
        "seen_pdf_codes": len(seen_pdf_codes_report),
        "seen_pdf_candidates_all": len(seen_pdf_codes_all),
        "price_col": price_col,
        "total_pages": total_pages,
        "compress_requested": False,
        "compression_applied": compression_applied,
        "compression_quality": "Nenaudojamas",
        "compression_message": compression_message,
        "original_size_mb": original_size_mb,
        "final_size_mb": final_size_mb,
    }
